clear();

let hosts = [
    '8.8.8.8',
    '1.1.1.1',
    '208.67.222.222',
];

ping(hosts);

return null;

function addHostKey(host) {
    let allHosts = flow.get('all_hosts') || [];
    allHosts.push(`host_${host.replaceAll('.', '_')}`);
    flow.set('all_hosts', allHosts);
}

function clear() {
    flow.set('all_hosts', null);

    flow.keys().forEach(key => {
        if (key.startsWith('host_')) {
            flow.set(key, undefined);
        }
    });
}

function ping(hosts) {
    for (const host of hosts) {
        addHostKey(host);
        msg.host = host;
        node.send(msg, true);
    }
}

const all_hosts = flow.get('all_hosts');

// Record this host's result
flow.set(`host_${msg.host.replaceAll('.', '_')}`, msg.payload);

if (!isComplete()) return null;

const timestamp = new Date().toISOString();
const source = 'connectivity_monitor';
const messages = [];

// Per-host state messages
for (const hostKey of all_hosts) {
    const rtt = flow.get(hostKey);
    const ip = hostKey.replace('host_', '').replaceAll('_', '.');
    const topicKey = hostKey.replace('host_', '');

    messages.push({
        topic: `highland/state/network/ping/${topicKey}`,
        payload: JSON.stringify({
            timestamp,
            source,
            state: rtt !== false ? 'up' : 'down',
            rtt: rtt !== false ? rtt : null
        }),
        retain: true,
        qos: 1
    });
}

// Aggregate connectivity state
const results = all_hosts.map(h => flow.get(h));
const upCount = results.filter(r => r !== false).length;
const aggregateState = upCount === all_hosts.length ? 'up'
    : upCount === 0 ? 'down'
    : 'degraded';

// Connectivity changed event
const previousState = flow.get('connectivity_state');
if (previousState !== aggregateState) {
    flow.set('connectivity_state', aggregateState);
    messages.push({
        topic: 'highland/event/network/connectivity_changed',
        payload: JSON.stringify({
            timestamp,
            source,
            previous: previousState || 'unknown',
            current: aggregateState
        }),
        retain: false,
        qos: 1
    });
}

// Aggregate state message
messages.push({
    topic: 'highland/state/network/connectivity',
    payload: JSON.stringify({
        timestamp,
        source,
        state: aggregateState
    }),
    retain: true,
    qos: 1
});

// Emit all messages
for (let i = 0; i < messages.length - 1; i++) {
    node.send(messages[i]);
}

msg.topic = messages[messages.length - 1].topic;
msg.payload = messages[messages.length - 1].payload;
msg.retain = messages[messages.length - 1].retain;
msg.qos = messages[messages.length - 1].qos;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
node.status({ 
    fill: aggregateState === 'up' ? 'green' : aggregateState === 'degraded' ? 'yellow' : 'red', 
    shape: 'dot', 
    text: formatStatus(aggregateState.toUpperCase()) 
});

return msg;

function isComplete() {
    return all_hosts.every(host => flow.get(host) !== undefined);
}

const raw_results = msg.payload;
const downstream_mbps = Math.round(raw_results.download.bandwidth * 8 / 1000000);
const upstream_mbps = Math.round(raw_results.upload.bandwidth * 8 / 1000000);

msg.results = {
    throughput: {
        downstream: downstream_mbps,
        upstream: upstream_mbps
    },
    ping: {
        jitter: raw_results.ping.jitter,
        latency: raw_results.ping.latency,
        packet_loss: raw_results.packetLoss ?? 0
    }
};

msg.topic = 'highland/state/network/speedtest';
msg.payload = JSON.stringify({
    timestamp: raw_results.timestamp,
    source: 'speedtest_monitor',
    throughput: msg.results.throughput,
    ping: msg.results.ping,
    server: {
        name: raw_results.server.name,
        location: raw_results.server.location
    },
    result_url: raw_results.result.url
});
msg.retain = true;
msg.qos = 1;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
node.status({ fill: 'green', shape: 'dot', text: formatStatus(`↓${downstream_mbps} ↑${upstream_mbps} Mbps`) });

return msg;

